const fileName = $input.first().json.name;
const parts = fileName.split('_');
const isbn = parts[0];
const fileId = $input.first().json.id;
const fileUrl = $input.first().json.webViewLink;
const mimeType = $input.first().json.mimeType;

if (!isbn) {
  return [{
    json: {
      error: true,
      message: `Invalid filename format: ${fileName}`,
      fileName
    }
  }];
}

return [{
  json: {
    isbn,
    fileId,
    fileName,
    fileUrl,
    mimeType,
    timestamp: new Date().toISOString()
  }
}];

const allRows = $input.all();
const extractData = $('Extract ISBN').first().json;
const isbn = extractData.isbn;

const match = allRows.find(row => 
  row.json['ISBN']?.toString() === isbn?.toString()
);

if (!match) {
  return [{
    json: {
      isbn,
      authorName: 'Unknown Author',
      authorEmail: null,
      fileId: extractData.fileId,
      fileName: extractData.fileName,
      fileUrl: extractData.fileUrl,
      mimeType: extractData.mimeType,
      timestamp: extractData.timestamp
    }
  }];
}

return [{
  json: {
    isbn,
    authorName: match.json['Author Name'],
    authorEmail: match.json['Author Email'],
    fileId: extractData.fileId,
    fileName: extractData.fileName,
    fileUrl: extractData.fileUrl,
    mimeType: extractData.mimeType,
    timestamp: extractData.timestamp
  }
}];

const binaryKey = Object.keys($input.first().binary)[0];
const mimeType = $input.first().binary[binaryKey].mimeType || 'image/png';

const buffer = await helpers.getBinaryDataBuffer(0, binaryKey);
const base64String = buffer.toString('base64');

return [{
  json: {
    ...$('Match Author').first().json,
    base64Image: base64String,
    imageMimeType: mimeType
  }
}];

