const rawResponse = $input.first().json;

// Handle if response is array or object
const geminiResponse = Array.isArray(rawResponse) ? rawResponse[0] : rawResponse;
const authorData = $('Match Author').first().json;

const rawText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
let analysis;
try {
  const cleaned = rawText.replace(/```json|```/g, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = {
    status: 'REVIEW NEEDED',
    confidence_score: 0,
    critical_issues: [{
      type: 'parse_error',
      severity: 'moderate',
      description: 'Could not analyze cover automatically',
      correction: 'Please review manually'
    }],
    summary: 'Automatic analysis failed - manual review required'
  };
}

const issuesText = analysis.critical_issues?.length > 0
  ? analysis.critical_issues.map(i => 
      `${i.severity === 'critical' ? '❌' : '⚠️'} ${i.description}`
    ).join('\n')
  : 'No issues detected';

const corrections = analysis.critical_issues?.length > 0
  ? analysis.critical_issues.map((i, idx) => 
      `${idx + 1}. ${i.correction}`
    ).join('\n')
  : 'Your cover meets all requirements.';

return [{
  json: {
    ...authorData,
    status: analysis.status,
    confidenceScore: analysis.confidence_score,
    issuesFound: issuesText,
    correctionInstructions: corrections,
    summary: analysis.summary,
    rawAnalysis: JSON.stringify(analysis)
  }
}];

